pub enum Capability {
    HttpCall = 0,
    Llm = 1,
    ZkCall = 5,
    Dkms = 6,
    ImageCall = 7,
    AudioCall = 8,
    VideoCall = 9,
    Fhe = 10,
}

pub fn is_executor_capability(&self) -> bool {
    matches!(self, Capability::HttpCall | Capability::Llm | Capability::WormholeQuery | Capability::ZkCall | Capability::ImageCall | Capability::AudioCall | Capability::VideoCall | Capability::Fhe)
}

let expected = Capability::try_from(metadata.expected_capability_tag().as_u8()).map_err(|_| { ... })?;
let executor = read_executor(db, registry, executor_address)?
    .ok_or_else(|| format!("TEE executor {executor_address} not found"))?;
if executor.capability != expected {
    return Err(format!("TEE executor {executor_address} has capability {:?}, expected {:?}", executor.capability, expected));
}
